import { Form, Link, useActionData, useNavigation } from '@remix-run/react';
import type { ActionFunction, MetaFunction } from '@remix-run/node';
import { useState } from 'react';

export const meta: MetaFunction = () => [
  { title: 'Register - Goal Tracker' },
];

import { User } from '../models/User';
import { UserPsychologyProfile } from '../models/Analytics';
import { hashPassword, isValidEmail, validatePasswordStrength } from '../utils/auth';
import { createUserSession } from '../services/auth.server';

export const action: ActionFunction = async ({ request }) => {
  if (request.method !== 'POST') {
    return null;
  }

  const formData = await request.formData();
  const email = formData.get('email') as string;
  const password = formData.get('password') as string;
  const confirmPassword = formData.get('confirmPassword') as string;

  if (password !== confirmPassword) {
    return { error: 'Passwords do not match' };
  }

  if (!isValidEmail(email)) {
    return { error: 'Invalid email format' };
  }

  const passwordStrength = validatePasswordStrength(password);
  if (!passwordStrength.valid) {
    return { error: 'Password is too weak', feedback: passwordStrength.feedback };
  }

  try {
    const existingUser = await User.findOne({ email: email.toLowerCase() });

    if (existingUser) {
      return { error: 'Email already registered' };
    }

    const password_hash = await hashPassword(password);

    const user = new User({
      email: email.toLowerCase(),
      password_hash,
      total_points: 0,
      current_level: 1,
      streak_count: 0,
    });

    await user.save();

    const profile = new UserPsychologyProfile({
      user_id: user._id,
      chronotype: 'afternoon',
      emotional_baseline: 5,
      energy_baseline: 5,
    });

    await profile.save();

    return createUserSession({
      request,
      userId: user._id.toString(),
      remember: true,
      redirectTo: '/dashboard',
    });
  } catch (error) {
    console.error('Registration error:', error);
    return { error: 'An error occurred. Please try again.' };
  }
};

export default function RegisterPage() {
  const actionData = useActionData<typeof action>();
  const navigation = useNavigation();
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const isLoading = navigation.state === 'submitting';

  return (
    <div className="flex min-h-screen items-center justify-center bg-gradient-to-b from-blue-50 to-white px-4">
      <div className="w-full max-w-md space-y-8">
        <div className="text-center">
          <h1 className="text-4xl font-bold text-gray-900">Goal Tracker</h1>
          <p className="mt-2 text-gray-600">Create your account to get started</p>
        </div>

        <Form method="post" className="space-y-6 rounded-lg border border-gray-200 bg-white p-8 shadow-sm">
          {actionData?.error && (
            <div className="rounded-md bg-red-50 p-4 text-sm text-red-700">
              {actionData.error}
            </div>
          )}

          <div>
            <label htmlFor="email" className="block text-sm font-medium text-gray-700">
              Email
            </label>
            <input
              type="email"
              id="email"
              name="email"
              required
              className="mt-2 block w-full rounded-md border border-gray-300 px-3 py-2 text-gray-900 placeholder-gray-400 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
              placeholder="you@example.com"
            />
          </div>

          <div>
            <label htmlFor="password" className="block text-sm font-medium text-gray-700">
              Password (min 8 characters)
            </label>
            <div className="relative">
              <input
                type={showPassword ? 'text' : 'password'}
                id="password"
                name="password"
                required
                minLength={8}
                className="mt-2 block w-full rounded-md border border-gray-300 px-3 py-2 text-gray-900 placeholder-gray-400 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
                placeholder="••••••••"
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
              >
                {showPassword ? '👁️' : '👁️‍🗨️'}
              </button>
            </div>
          </div>

          <div>
            <label htmlFor="confirmPassword" className="block text-sm font-medium text-gray-700">
              Confirm Password
            </label>
            <div className="relative">
              <input
                type={showConfirm ? 'text' : 'password'}
                id="confirmPassword"
                name="confirmPassword"
                required
                minLength={8}
                className="mt-2 block w-full rounded-md border border-gray-300 px-3 py-2 text-gray-900 placeholder-gray-400 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
                placeholder="••••••••"
              />
              <button
                type="button"
                onClick={() => setShowConfirm(!showConfirm)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
              >
                {showConfirm ? '👁️' : '👁️‍🗨️'}
              </button>
            </div>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full rounded-md bg-blue-600 px-4 py-2 text-white font-medium hover:bg-blue-700 disabled:opacity-50 transition"
          >
            {isLoading ? 'Creating account...' : 'Create account'}
          </button>
        </Form>

        <p className="text-center text-sm text-gray-600">
          Already have an account?{' '}
          <Link to="/auth/login" className="font-medium text-blue-600 hover:text-blue-700">
            Sign in
          </Link>
        </p>
      </div>
    </div>
  );
}
